404:     private MemoryRecordsBuilder recordsBuilder(ByteBuffer buffer) {
405:         return MemoryRecords.builder(buffer, RecordBatch.CURRENT_MAGIC_VALUE, compression, TimestampType.CREATE_TIME, 0L);
